-- список подчиненных для пользователя CREATE FUNCTION [GetOrganizationItemUsers] ( @OrganizationItemId bigint ) RETURNS TABLE AS RETURN (
-- для долджностей возврящаем пользователей назначенных на должности select oi.UserId from OrganizationItem oi with (nolock) where oi.ItemType = 1 and oi.Id = @OrganizationItemId and oi.UserId is not null union select s.UserId from OrganizationItem oi with (nolock) cross apply [GetDepartmentUsers](oi.Id) s where (oi.ItemType = 0 or oi.ItemType = 2) and oi.Id = @OrganizationItemId
)

CREATE PROCEDURE FillUserSecuritySetCache AS BEGIN SET NOCOUNT ON;
declare @typemask bigint, @usermask bigint, @groupmask bigint, @organizationitemmask bigint; -- маска которая оставляет только биты типа set @typemask = 9151314442816847872; -- побитовый сдвиг влево 1111111 на 56 разрядов (2 ^ 56) 1111111[0]55 -- маска начальников пользователя set @usermask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55 -- маска группы set @groupmask = 144115188075855872; -- побитовый сдвиг влево 10 на 56 разрядов (2 ^ 56) 10[0]55 -- маска отдела set @organizationitemmask = 216172782113783808; -- побитовый сдвиг влево 11 на 56 разрядов (2 ^ 56) 11[0]55
-- удаляем из кэша старые записи delete from UserSecuritySetCacheTemp;
-- начальники пользователей insert into UserSecuritySetCacheTemp (SetId, UserId, SubordinateUserId, Subordinate, UserCount) select SetId, UserId, SubordinateUserId, Min(Subordinate), -1 from ( select (u.Id | @usermask) as SetId, u.Id as UserId, u.Id as SubordinateUserId, 0 as Subordinate from [User] u union select (s.UserId | @usermask), u.Id, s.UserId, 1 from [user] u cross apply [GetUserSubordinate](u.Id) s ) s group by SetId, UserId, SubordinateUserId;
-- подразделения with DepartmentUsers as ( select Id, UserId, UserCount from GetDepartmentsUsers() ) insert into UserSecuritySetCacheTemp (SetId, UserId, OrgItemId, Subordinate, UserCount) select (Id|@organizationitemmask), UserId, Id, Min(Subordinate), Max(UserCount) from ( select Id, UserId, UserCount, 0 as Subordinate from DepartmentUsers union select gu.Id, ussc.UserId, -1, 1 from DepartmentUsers gu inner join UserSecuritySetCacheTemp ussc on ussc.SubordinateUserId = gu.UserId ) s group by Id, UserId;
-- группы with GroupUsers as ( select GroupId Id, UserId, UserCount from GetGroupsUsers() ) insert into UserSecuritySetCacheTemp (SetId, UserId, GroupId, Subordinate, UserCount) select (Id|@groupmask), UserId, Max(GroupId), Min(Subordinate), Max(UserCount) from ( select Id, Id GroupId, UserId, UserCount, 0 as Subordinate from GroupUsers union select gu.Id, null, ussc.UserId, -1, 1 from GroupUsers gu inner join UserSecuritySetCacheTemp ussc on ussc.SubordinateUserId = gu.UserId ) s group by Id, UserId;
-- переносим данные из кэша в боевую таблицу delete from UserSecuritySetCache where not exists(select SetId from UserSecuritySetCacheTemp t where t.SetId=UserSecuritySetCache.SetId and t.UserId=UserSecuritySetCache.UserId and t.Subordinate=UserSecuritySetCache.Subordinate and t.UserCount=UserSecuritySetCache.UserCount); insert into UserSecuritySetCache (SetId, UserId, SubordinateUserId, Subordinate, GroupId, OrgItemId, UserCount) select t.SetId, t.UserId, t.SubordinateUserId, t.Subordinate, t.GroupId, t.OrgItemId, t.UserCount from UserSecuritySetCacheTemp t left join UserSecuritySetCache c on t.SetId=c.SetId and t.UserId=c.UserId and t.Subordinate=c.Subordinate and t.UserCount=c.UserCount where c.SetId is null;
END


CREATE PROCEDURE [UpdateUserSecuritySetCache]
  @UpdateData varchar(max),
  @AuditUid uniqueidentifier
AS
BEGIN
  SET NOCOUNT ON;

  declare @typemask bigint, @usermask bigint, @groupmask bigint, @organizationitemmask bigint;
  -- маска которая оставляет только биты типа
  set @typemask = 9151314442816847872; -- побитовый сдвиг влево 1111111 на 56 разрядов (2 ^ 56) 1111111[0]55
  -- маска начальников пользователя
  set @usermask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55
  -- маска группы
  set @groupmask = 144115188075855872; -- побитовый сдвиг влево 10 на 56 разрядов (2 ^ 56) 10[0]55
  -- маска отдела
  set @organizationitemmask = 216172782113783808; -- побитовый сдвиг влево 11 на 56 разрядов (2 ^ 56) 11[0]55

  declare @refreshUsers bit;
  declare @separator int;
  declare @itemData nvarchar(max);
  declare @addUsersData nvarchar(max);
  declare @removeUsersData nvarchar(max);
  declare @addOrgItemsData nvarchar(max);
  declare @removeOrgItemsData nvarchar(max);
  declare @addGroupsData nvarchar(max);
  declare @removeGroupsData nvarchar(max);
  declare @itemId bigint;
  declare @subItemId bigint;

  delete from UUSSCGroupData;
  delete from UUSSCOrgItemData;

  set @refreshUsers = 0;

  -- парсим строку, записываем все во временную таблицу
  while patindex('%;%', @UpdateData) > 0
  begin
    set @separator = patindex('%;%', @UpdateData);
    set @itemData = left(@UpdateData, @separator - 1);
    set @UpdateData = stuff(@UpdateData, 1, @separator, '');

    set @separator = patindex('%:%', @itemData);
    if (@separator > 0)
    begin
      -- Данные для группы или элемента оргструктуры
      set @itemId = cast(left(@itemData, @separator - 1) as bigint);
      set @itemData = stuff(@itemData, 1, @separator, '');

      set @separator = patindex('%:%', @itemData);
      set @addUsersData = left(@itemData, @separator - 1);
      set @itemData = stuff(@itemData, 1, @separator, '');

      set @separator = patindex('%:%', @itemData);
      if (@separator > 0)
      begin
        -- Данные для группы

        set @removeUsersData = left(@itemData, @separator - 1);
        set @itemData = stuff(@itemData, 1, @separator, '');

        set @separator = patindex('%:%', @itemData);
        set @addOrgItemsData = left(@itemData, @separator - 1);
        set @itemData = stuff(@itemData, 1, @separator, '');

        set @separator = patindex('%:%', @itemData);
        set @removeOrgItemsData = left(@itemData, @separator - 1);
        set @itemData = stuff(@itemData, 1, @separator, '');

        set @separator = patindex('%:%', @itemData);
        set @addGroupsData = left(@itemData, @separator - 1);
        set @removeGroupsData = stuff(@itemData, 1, @separator, '');

        while patindex('%,%', @addUsersData) > 0
        begin
          set @separator = patindex('%,%', @addUsersData);
          set @subItemId = cast(left(@addUsersData, @separator - 1) as bigint);
          set @addUsersData = stuff(@addUsersData, 1, @separator, '');
          insert into UUSSCGroupData(Id, UserId, AddCount) values(@itemId, @subItemId, 1);
        end

        while patindex('%,%', @removeUsersData) > 0
        begin
          set @separator = patindex('%,%', @removeUsersData);
          set @subItemId = cast(left(@removeUsersData, @separator - 1) as bigint);
          set @removeUsersData = stuff(@removeUsersData, 1, @separator, '');
          insert into UUSSCGroupData(Id, UserId, AddCount) values(@itemId, @subItemId, -1);
        end

        while patindex('%,%', @addOrgItemsData) > 0
        begin
          set @separator = patindex('%,%', @addOrgItemsData);
          set @subItemId = cast(left(@addOrgItemsData, @separator - 1) as bigint);
          set @addOrgItemsData = stuff(@addOrgItemsData, 1, @separator, '');
          insert into UUSSCGroupData(Id, OrgItemId, AddCount) values(@itemId, @subItemId, 1);
        end

        while patindex('%,%', @removeOrgItemsData) > 0
        begin
          set @separator = patindex('%,%', @removeOrgItemsData);
          set @subItemId = cast(left(@removeOrgItemsData, @separator - 1) as bigint);
          set @removeOrgItemsData = stuff(@removeOrgItemsData, 1, @separator, '');
          insert into UUSSCGroupData(Id, OrgItemId, AddCount) values(@itemId, @subItemId, -1);
        end

        while patindex('%,%', @addGroupsData) > 0
        begin
          set @separator = patindex('%,%', @addGroupsData);
          set @subItemId = cast(left(@addGroupsData, @separator - 1) as bigint);
          set @addGroupsData = stuff(@addGroupsData, 1, @separator, '');
          insert into UUSSCGroupData(Id, GroupId, AddCount) values(@itemId, @subItemId, 1);
        end

        while patindex('%,%', @removeGroupsData) > 0
        begin
          set @separator = patindex('%,%', @removeGroupsData);
          set @subItemId = cast(left(@removeGroupsData, @separator - 1) as bigint);
          set @removeGroupsData = stuff(@removeGroupsData, 1, @separator, '');
          insert into UUSSCGroupData(Id, GroupId, AddCount) values(@itemId, @subItemId, -1);
        end
      end
      else
      begin
        -- Данные для элемента оргструктуры

        set @removeUsersData = stuff(@itemData, 1, @separator, '');

        while patindex('%,%', @addUsersData) > 0
        begin
          set @separator = patindex('%,%', @addUsersData);
          set @subItemId = cast(left(@addUsersData, @separator - 1) as bigint);
          set @addUsersData = stuff(@addUsersData, 1, @separator, '');
          insert into UUSSCOrgItemData(Id, UserId, AddCount) values(@itemId, @subItemId, 1);
        end

        while patindex('%,%', @removeUsersData) > 0
        begin
          set @separator = patindex('%,%', @removeUsersData);
          set @subItemId = cast(left(@removeUsersData, @separator - 1) as bigint);
          set @removeUsersData = stuff(@removeUsersData, 1, @separator, '');
          insert into UUSSCOrgItemData(Id, UserId, AddCount) values(@itemId, @subItemId, -1);
        end
      end
    end
    else
    begin
      -- Нужно обновить данные по пользователям
      set @refreshUsers = 1;
    end
  end

  -- удаляем из кэша старые записи
  delete from UserSecuritySetCacheTemp;

  if (exists(select Id from UUSSCOrgItemData))
  begin
    -- рекурсивное добавление данных для содержащих отделов
    insert into UUSSCOrgItemData(Id, UserId, AddCount)
    select g.DepartmentId, d.UserId, d.AddCount from UUSSCOrgItemData d
    inner join (select * from GetDepartments() where Id<>DepartmentId) g on g.Id=d.Id;


    -- начальники пользователей
    insert into UserSecuritySetCacheTemp (SetId, UserId, SubordinateUserId, Subordinate, UserCount)
    select SetId, UserId, SubordinateUserId, Min(Subordinate), -1 from
    (
      select (u.Id | @usermask) as SetId, u.Id as UserId, u.Id as SubordinateUserId, 0 as Subordinate from [User] u
      union
      select (s.UserId | @usermask), u.Id, s.UserId, 1 from [user] u 
      cross apply [GetUserSubordinate](u.Id) s
    ) s group by SetId, UserId, SubordinateUserId;


    -- дублируем текущие записи об элементах орг структуры (без учета подчиненных пользователей)
    insert into UserSecuritySetCacheTemp (SetId, UserId, SubordinateUserId, Subordinate, GroupId, OrgItemId, UserCount)
    select SetId, UserId, SubordinateUserId, Subordinate, t.GroupId, OrgItemId, UserCount
    from UserSecuritySetCache t
    where t.OrgItemId in (select Id from UUSSCOrgItemData) and t.Subordinate=0;

    -- добавляем тех пользователей, которых нет в таблице
    insert into UserSecuritySetCacheTemp (SetId, UserId, OrgItemId, Subordinate, UserCount)
    select (d.Id|@organizationitemmask), d.UserId, d.Id, 0, 0
    from UUSSCOrgItemData d
    left join UserSecuritySetCacheTemp t on t.OrgItemId=d.Id and t.UserId=d.UserId
    where d.UserId is not null and t.OrgItemId is null
    group by d.Id, d.UserId;

    -- изменяем количество ссылок на пользователей
    update UserSecuritySetCacheTemp
    set UserCount=UserCount+d.AddCount
    from UserSecuritySetCacheTemp t
    inner join (select Id, UserId, SUM(AddCount) AddCount from UUSSCOrgItemData group by Id, UserId) d on t.OrgItemId=d.Id and t.UserId=d.UserId;


    -- переводим изменения по элементам оргстуктуры в изменения по группам
    insert into UUSSCGroupData(Id, UserId, AddCount)
    select m.GroupId, d.UserId, d.AddCount from UUSSCOrgItemData d
    left join UserGroup_OrgItem_Map m on m.OrgItemId=d.Id
    where m.GroupId is not null;
  end
  else if (@refreshUsers = 1)
  begin
    -- начальники пользователей
    insert into UserSecuritySetCacheTemp (SetId, UserId, SubordinateUserId, Subordinate, UserCount)
    select SetId, UserId, SubordinateUserId, Min(Subordinate), -1 from
    (
      select (u.Id | @usermask) as SetId, u.Id as UserId, u.Id as SubordinateUserId, 0 as Subordinate from [User] u
      union
      select (s.UserId | @usermask), u.Id, s.UserId, 1 from [user] u 
      cross apply [GetUserSubordinate](u.Id) s
    ) s group by SetId, UserId, SubordinateUserId;
  end

  -- переводим идентификаторы элементов оргструктуры в идентификаторы пользователей
  insert into UUSSCGroupData(Id, UserId, AddCount)
  select d.Id, c.UserId, d.AddCount from UUSSCGroupData d
  inner join UserSecuritySetCache c on c.OrgItemId = d.OrgItemId and c.Subordinate=0;

  -- переводим идентификаторы групп в идентификаторы пользователей
  insert into UUSSCGroupData(Id, UserId, AddCount)
  select d.Id, c.UserId, d.AddCount * c.UserCount from UUSSCGroupData d
  inner join UserSecuritySetCache c on c.GroupId = d.GroupId and c.Subordinate=0;

  -- рекурсивное добавление данных для родительских групп
  insert into UUSSCGroupData(Id, UserId, AddCount)
  select g.ChildGroupId, d.UserId, d.AddCount from UUSSCGroupData d
  inner join (select * from GetGroups() where ChildGroupId<>ParentGroupId) g on g.ParentGroupId=d.Id;


  -- дублируем текущие записи о группах (без учета подчиненных пользователей)
  insert into UserSecuritySetCacheTemp (SetId, UserId, SubordinateUserId, Subordinate, GroupId, OrgItemId, UserCount)
  select SetId, UserId, SubordinateUserId, Subordinate, t.GroupId, OrgItemId, UserCount
  from UserSecuritySetCache t
  where t.GroupId in (select Id from UUSSCGroupData) and t.Subordinate=0;

  -- добавляем тех пользователей, которых нет в таблице
  insert into UserSecuritySetCacheTemp (SetId, UserId, GroupId, Subordinate, UserCount)
  select (d.Id|@groupmask), d.UserId, d.Id, 0, 0
  from UUSSCGroupData d
  left join UserSecuritySetCacheTemp t on t.GroupId=d.Id and t.UserId=d.UserId
  where d.UserId is not null and t.GroupId is null
  group by d.Id, d.UserId;

  -- изменяем количество ссылок на пользователей
  update UserSecuritySetCacheTemp
  set UserCount=UserCount+d.AddCount
  from UserSecuritySetCacheTemp t
  inner join (select Id, UserId, SUM(AddCount) AddCount from UUSSCGroupData group by Id, UserId) d on t.GroupId=d.Id and t.UserId=d.UserId;

  -- удаляем записи без ссылок
  delete from UserSecuritySetCacheTemp where UserCount<=0 and SubordinateUserId is null;

  DECLARE @IsSubordinate int;

  SET @IsSubordinate = 0;
  -- переносим данные из кэша в боевую таблицу
  if (exists(select Id from UUSSCOrgItemData))
  begin
    insert into UserSecuritySetCacheTemp (SetId, UserId, GroupId, OrgItemId, Subordinate, UserCount)
    -- добавляем записи подчиненных пользователей для измененных данных (подчинения берем из временной таблицы, в ней актуальные данные)
    select t.SetId, ussc.UserId, null, t.OrgItemId, 1, -1 from UserSecuritySetCacheTemp t
    inner join UserSecuritySetCacheTemp ussc on ussc.SubordinateUserId = t.UserId
    left join UserSecuritySetCacheTemp st on st.SetId = t.SetId and st.UserId = ussc.UserId
    where st.SetId is null and t.SubordinateUserId is null
    union
    -- добавляем записи подчиненных пользователей для данных, которые не меняются (подчинения берем из временной таблицы, в ней актуальные данные)
    select t.SetId, ussc.UserId, null, t.OrgItemId, 1, -1 from UserSecuritySetCache t
    inner join UserSecuritySetCacheTemp ussc on ussc.SubordinateUserId = t.UserId
    left join UserSecuritySetCache st on st.SetId = t.SetId and st.UserId = ussc.UserId and st.Subordinate=0
    left join UUSSCOrgItemData oid on t.OrgItemId=oid.Id
    left join UUSSCGroupData gd on t.GroupId=gd.Id
    where t.Subordinate=0 and st.SetId is null and oid.Id is null and gd.Id is null and t.SubordinateUserId is null;

	  SET @IsSubordinate = 2;

  end
  else if (@refreshUsers = 1)
  begin
    insert into UserSecuritySetCacheTemp (SetId, UserId, GroupId, OrgItemId, Subordinate, UserCount)
    -- добавляем записи подчиненных пользователей для измененных данных (подчинения берем из временной таблицы, в ней актуальные данные)
    select t.SetId, ussc.UserId, null, t.OrgItemId, 1, -1 from UserSecuritySetCacheTemp t
    inner join UserSecuritySetCacheTemp ussc on ussc.SubordinateUserId = t.UserId
    left join UserSecuritySetCacheTemp st on st.SetId = t.SetId and st.UserId = ussc.UserId
    where st.SetId is null and t.SubordinateUserId is null
    union
    -- добавляем записи подчиненных пользователей для данных, которые не меняются (подчинения берем из временной таблицы, в ней актуальные данные)
    select t.SetId, ussc.UserId, null, t.OrgItemId, 1, -1 from UserSecuritySetCache t
    inner join UserSecuritySetCacheTemp ussc on ussc.SubordinateUserId = t.UserId
    left join UserSecuritySetCache st on st.SetId = t.SetId and st.UserId = ussc.UserId and st.Subordinate=0
    left join UUSSCOrgItemData oid on t.OrgItemId=oid.Id
    left join UUSSCGroupData gd on t.GroupId=gd.Id
    where t.Subordinate=0 and st.SetId is null and oid.Id is null and gd.Id is null and t.SubordinateUserId is null;

	  SET @IsSubordinate = 1;

  end
  else
  begin
    -- добавляем записи подчиненных пользователей (подчинения берем из основной таблице, они не меняются в текущей итерации)
    insert into UserSecuritySetCacheTemp (SetId, UserId, GroupId, OrgItemId, Subordinate, UserCount)
    select distinct t.SetId, ussc.UserId, null, t.OrgItemId, 1, -1 from UserSecuritySetCacheTemp t
    inner join UserSecuritySetCache ussc on ussc.SubordinateUserId = t.UserId
    left join UserSecuritySetCacheTemp st on st.SetId = t.SetId and st.UserId = ussc.UserId
    where st.SetId is null;
  end

  -- удаляем данные по измененным группам
  update UUSSCGroupData set SetId=Id|@groupmask;

  -- сохраняем изменения пользователей в группах для аудита
  INSERT INTO HistoryUserSecuritySetCache(Id, UserId, OrgItemId, GroupId, SetId, [Uid], AddCount)
  SELECT g.Id, g.UserId, g.OrgItemId, g.GroupId, g.SetId, @AuditUid, AddCount
  FROM UUSSCGroupData g
  LEFT JOIN UserSecuritySetCacheTemp c	 
  ON c.SetId = g.SetId AND c.UserId = g.UserId
  WHERE (g.UserId IS NOT NULL OR g.OrgItemId IS NOT NULL OR g.GroupId IS NOT NULL) 
			AND (ISNULL(c.UserCount, g.AddCount) - g.AddCount = 0 or G.UserId IS NULL)

  IF @IsSubordinate > 0
  BEGIN
	-- удаляем из основной таблицы все данные по подчинениям по элементам оргструктуры и группам
    delete from UserSecuritySetCache where Subordinate=1;

    -- удаляем начальников пользователей (эти данные есть во временной табилце)
    delete from UserSecuritySetCache where SetId&@typemask=@usermask;

    IF @IsSubordinate > 1
    BEGIN
		-- удаляем данные по измененным элементам оргструктуры
		update UUSSCOrgItemData set SetId=Id|@organizationitemmask;
		delete from UserSecuritySetCache where SetId in (select SetId from UUSSCOrgItemData t);
    END
  END

  delete from UserSecuritySetCache where SetId in (select SetId from UUSSCGroupData t);

  -- добавляем все, что есть во временной таблице (предварительно все лишние данные были удалены)
  insert into UserSecuritySetCache (SetId, UserId, SubordinateUserId, Subordinate, GroupId, OrgItemId, UserCount) select SetId, UserId, SubordinateUserId, Subordinate, GroupId, OrgItemId, UserCount from UserSecuritySetCacheTemp t;

  INSERT INTO HistoryUserSecuritySetCache(Uid)
  VALUES(@AuditUid);
END
